const express = require('express');
const axios = require('axios');

const app = express();
app.use(express.json());

const PORT = process.env.PORT || 3000;
const PREMBLY_BASE_URL = process.env.PREMBLY_BASE_URL || 'https://api.prembly.com';
const PREMBLY_APP_ID = process.env.PREMBLY_APP_ID;
const PREMBLY_API_KEY = process.env.PREMBLY_API_KEY;

const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

async function verifyNinWithRetry(nin, retries = 3) {
  const delays = [100, 200, 400];

  for (let i = 0; i <= retries; i++) {
    try {
      const response = await axios.post(
        `${PREMBLY_BASE_URL}/verification/nin`,
        { nin },
        {
          headers: {
            'app-id': PREMBLY_APP_ID,
            'x-api-key': PREMBLY_API_KEY,
            'Content-Type': 'application/json',
          },
        }
      );
      return { status: 200, data: response.data };
    } catch (error) {
      if (error.response && error.response.status === 429 && i < retries) {
        console.log(`Rate limited. Retrying in ${delays[i]}ms... (Attempt ${i + 1})`);
        await sleep(delays[i]);
        continue;
      }

      if (error.response) {
        return { status: error.response.status, data: error.response.data };
      }
      return { status: 500, data: { message: error.message } };
    }
  }
}

app.post('/verify-nin', async (req, res) => {
  const { nin } = req.body;

  if (!nin) {
    return res.status(400).json({ message: 'NIN is required' });
  }

  const result = await verifyNinWithRetry(nin);

  if (result.status === 429) {
    return res.status(429).json({ message: 'Rate limit exceeded, please try again later' });
  }

  res.status(result.status).json(result.data);
});

app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});

